Here's a Python function that uses a stack to check for valid parentheses:
```python
def valid_parentheses(s):
    stack = []
    for char in s:
        if char == '(':
            stack.append(char)
        elif char == ')':
            if not stack or stack[-1] != '(':
                return False
            else:
                stack.pop()
        elif char == '{':
            stack.append(char)
        elif char == '}':
            if not stack or stack[-1] != '{':
                return False
            else:
                stack.pop()
        elif char == '<':
            stack.append(char)
        elif char == '>':
            if not stack or stack[-1] != '<':
                return False
            else:
                stack.pop()
    return len(stack) == 0
```
